commands.cmd:
ids=$(timeout 20 docker network ls -q) || { echo "docker network ls failed" >&2; exit 1; }
if [ -z "$ids" ]; then
  printf '{"dangling_networks":0,"results":[]}'
else
  inspect_out=$(timeout 20 docker network inspect $ids) || { echo "docker network inspect failed" >&2; exit 1; }
  printf '%s' "$inspect_out" | jq -c '
    [ .[]
      | select(.Name != "bridge" and .Name != "host" and .Name != "none" and .Name != "docker_gwbridge")
      | select(.Ingress != true)
      | select((.Containers | length) == 0)
      | { name: .Name, driver: .Driver }
    ] as $dangling
    | {
        dangling_networks: ($dangling | length),
        results: ($dangling[0:50])
      }
  ' || { echo "jq failed" >&2; exit 1; }
fi
